window.ASBAB_NUZUL_CACHE["31"] = {"asbab_nuzul":{"15":[{"ar":"عَنْ مُصْعَبُ بْنُ سَعْدٍ عَنْ أَبِيه وذكر الحديث. (انظر سورة العنكبوت آية ٨، وسورة المائدة آية ٩٠ وتخريجه هناك)","id":""}]},"mapping_ayat":{"31:13":[{"p":"Bukhari","n":31,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ ح قَالَ و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا لَمْ يَظْلِمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dan juga telah meriwayatkan hadits yang serupa ini, Telah menceritakan kepadaku [Bisyir bin Khalid Abu Muhammad Al 'Asykari] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: ketika turun ayat: \"Orang-orang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman\" para sahabat Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah diantara kami yang tidak berbuat zhalim? Maka Allah 'azza wajalla menurunkan (firman-Nya): \"Sesungguhnya kesyirikan adalah kezhaliman yang besar\". (QS. Luqman: 13) "},{"p":"Bukhari","n":3117,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَنَزَلَتْ{ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah bercerita kepada kami [Abu Al Walid] telah bercerita kepada kami [Syu'bah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata; \"Ketika turun firman Allah Ta'ala yang artinya: (\"Orang-orang yang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman ….\") (QS al-An'am ayat 82), para sahabat Nabi shallallahu 'alaihi wasallam berkata; \"Siapa diantara kita yang tidak mencampur adukkan imannya dengan kezhaliman?\". Maka kemudian Allah Ta'ala menurunkan firman-Nya: (\"Janganlah kamu berbuat syirik (menyekutukan Allah), karena sesungguhnya syirik itu benar-benar kezhaliman yang besar\"). (QS Luqman ayat 13)."},{"p":"Bukhari","n":3118,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا لَا يَظْلِمُ نَفْسَهُ قَالَ لَيْسَ ذَلِكَ إِنَّمَا هُوَ الشِّرْكُ أَلَمْ تَسْمَعُوا مَا قَالَ لُقْمَانُ لِابْنِهِ وَهُوَ يَعِظُهُ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah bercerita kepadaku [Ishaq] telah mengabarkan kepada kami ['Isa bin Yunus] telah bercerita kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata; \"Ketika turun firman Allah Ta'ala yang artinya: (\"Orang-orang yang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman ….\") (QS al-An'am ayat 82), membuat kaum muslimin menjadi ragu lalu mereka berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam, adakah orang di antara kami yang tidak menzhalimi dirinya?\". Maka beliau berkata: \"Bukan itu maksudnya. Sesungguhnya yang dimaksud dengan kezhaliman pada ayat itu adalah syirik. Apakah kalian belum pernah mendengar apa yang diucapkan Luqman kepada anaknya saat dia memberi pelajaran: (\"Wahai anakku, Janganlah kamu berbuat syirik (menyekutukan Allah), karena sesungguhnya syirik itu benar-benar kezhaliman yang besar\"). (QS Luqman ayat 13)."},{"p":"Bukhari","n":6073,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ بِذَاكَ أَلَا تَسْمَعُونَ إِلَى قَوْلِ لُقْمَانَ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Alqomah] dari [Abdullah] radliallahu 'anhu, mengatakan; 'Dikala diturunkan ayat; 'Sesungguhnya orang yang beriman dan tidak mencampur adukkan keimanan mereka dengan kezhaliman' (QS. Al an'am 82), para sahabat Nabi shallallahu 'alaihi wasallam merasa gusar, sehingga bertanya; 'Siapakah diantara kami yang tidak mencampur keimananya dengan kezjhaliman? ' Maka Rasulullah Shallallahu'alaihiwasallam menjawab; \"Bukan itu yang dimaksudkan, tidakkah kalian mendengar ucapan Luqman; 'sesungguhnya kesyirikan adalah kezhaliman yang besar\" (QS. Luqman 13) "},{"p":"Muslim","n":177,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَا يَظْلِمُ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ هُوَ كَمَا تَظُنُّونَ إِنَّمَا هُوَ كَمَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ ح و حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ إِدْرِيسَ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ قَالَ أَبُو كُرَيْبٍ قَالَ ابْنُ إِدْرِيسَ حَدَّثَنِيهِ أَوَّلًا أَبِي عَنْ أَبَانَ بْنِ تَغْلِبَ عَنْ الْأَعْمَشِ ثُمَّ سَمِعْتُهُ مِنْهُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dan [Abu Mu'awiyah] serta [Waki'] dari [al-A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dia berkata, \"Ketika turun ayat: '(Orang-orang yang beriman, dan iman mereka belum bercampur dengan kezhaliman) ' (Qs. Al An'am: 82), maka para sahabat merasa berat terhadap hal tersebut seraya berkata, 'Wahai Rasulullah, siapakah di antara kita yang tidak mendzalimi dirinya! ' Beliau menjawab: 'Hal itu tidaklah seperti yang kalian maksudkan. Ia adalah sebagaimana yang dikatakan Luqman kepada anaknya: '(Wahai anakku, janganlah kamu mensyirikkan Allah. Sesungguhnya syirik adalah kezhaliman yang besar) '. (Qs. Luqman: 13). Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Kasyram] keduanya berkata, telah mengabarkan kepada kami [Isa] yaitu -Ibnu Yunus-. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Minjab bin al-Harits at-Tamimi] telah mengabarkan kepada kami [Ibnu Mushir]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Idris] semuanya dari [al-A'masy] dengan sanad ini, [Abu Kuraib] berkata, [Ibnu Idris] berkata, telah menceritakan kepadaku tentangnya pertama kali [bapakku] dari [Aban bin Taghlib] dari [al-A'masy] kemudian aku mendengarnya darinya.\""},{"p":"Tirmidzi","n":2853,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ وَأَيُّنَا لَا يَظْلِمُ نَفْسَهُ قَالَ لَيْسَ ذَلِكَ إِنَّمَا هُوَ الشِّرْكُ أَلَمْ تَسْمَعُوا مَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khusyram] telah mengabarkan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; \"Saat turun ayat Orang-orang yang beriman dan tidak mencampuradukkan iman mereka dengan kezhaliman QS Al An`am: 82, kaum muslimin merasa berat karenanya dan bertanya; \"Wahai Rasulullah, adakah diantara kami yang tidak pernah mendzalimi dirinya?\" Beliau bersabda: \"Bukan begitu, maksudnya adalah syirk, bukankah kalian mendengar apa yang dikatakan Luqman kepada anaknya? Wahai anakku janganlah engkau mempersekutukan Allah, sesungguhnya syirik itu adalah kedzhaliman yang besar. QS Luqman: 13. Abu Isa mengatakan bahwa hadits ini hasan shahih."}],"31:31":[{"p":"Ahmad","n":1555,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ عَنْ عَامِرٍ أَوْ أَبِي عَامِرٍ أَوْ أَبِي مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي مَجْلِسٍ فِيهِ أَصْحَابُهُ جَاءَهُ جِبْرِيلُ عَلَيْهِ السَّلَام فِي غَيْرِ صُورَتِهِ يَحْسِبُهُ رَجُلًا مِنْ الْمُسْلِمِينَ فَسَلَّمَ عَلَيْهِ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ وَضَعَ جِبْرِيلُ يَدَهُ عَلَى رُكْبَتَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَهُ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ أَنْ تُسْلِمَ وَجْهَكَ لِلَّهِ وَتَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَسْلَمْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَالْمَلَائِكَةِ وَالْكِتَابِ وَالنَّبِيِّينَ وَالْمَوْتِ وَالْحَيَاةِ بَعْدَ الْمَوْتِ وَالْجَنَّةِ وَالنَّارِ وَالْحِسَابِ وَالْمِيزَانِ وَالْقَدَرِ كُلِّهِ خَيْرِهِ وَشَرِّهِ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ آمَنْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِحْسَانُ يَا رَسُولَ اللَّهِ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ كُنْتَ لَا تَرَاهُ فَهُوَ يَرَاكَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَحْسَنْتُ قَالَ نَعَمْ وَيَسْمَعُ رَجْعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ وَلَا يَرَى الَّذِي يُكَلِّمُهُ وَلَا يَسْمَعُ كَلَامَهُ قَالَ فَمَتَى السَّاعَةُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ خَمْسٌ مِنْ الْغَيْبِ لَا يَعْلَمُهَا إِلَّا اللَّهُ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ السَّائِلُ يَا رَسُولَ اللَّهِ إِنْ شِئْتَ حَدَّثْتُكَ بِعَلَامَتَيْنِ تَكُونَانِ قَبْلَهَا فَقَالَ حَدِّثْنِي فَقَالَ إِذَا رَأَيْتَ الْأَمَةَ تَلِدُ رَبَّهَا وَيَطُولُ أَهْلُ الْبُنْيَانِ بِالْبُنْيَانِ وَكَانَ الْعَالَةُ الْجُفَاةُ رُءُوسَ النَّاسِ قَالَ وَمَنْ أُولَئِكَ يَا رَسُولَ اللَّهِ قَالَ الْعَرِيبُ قَالَ ثُمَّ وَلَّى فَلَمْ يُرَ طَرِيقُهُ بَعْدُ قَالَ سُبْحَانَ اللَّهِ ثَلَاثًا جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا جَاءَ لِي قَطُّ إِلَّا وَأَنَا أَعْرِفُهُ إِلَّا أَنْ تَكُونَ هَذِهِ الْمَرَّةُحَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا عَبْدُ الْحَمِيدِ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ عَنِ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَصْنَافِ النِّسَاءِ فَذَكَرَ الْحَدِيثَ مُلْصِقًا بِهِ قَالَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَجْلِسًا فَأَتَى جِبْرِيلُ عَلَيْهِ السَّلَام فَجَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ وَقَالَ فِيهِ إِنْ شِئْتَ حَدَّثْتُكَ بِمَعَالِمَ لَهَا دُونَ ذَلِكَ قَالَ أَجَلْ يَا رَسُولَ اللَّهِ فَحَدِّثْنِي وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَ الْأَمَةَ وَلَدَتْ رَبَّتَهَا فَذَكَرَ الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abdullah bin Abu Husain] ia berkata, telah menceritakan kepadaku [Syahr bin Hausyab] dari [Amir] atau [Abu Amir] atau [Abu Malik], bahwa ketika Nabi shallallahu 'alaihi wasallam sedang duduk-duduk di masjlisnya bersama dengan para sahabat, malaikat Jibril Alaihis Salam datang kepada beliau dengan rupa yang berbeda. Sehingga beliau mengira bahwa itu adalah seorang laki-laki biasa dari kaum muslimin. Jibril 'Alaihis salam lantas mengucapkan salam kepada beliau dan beliau pun membalas salamnya. Kemudian Jibril meletakkan tangannya di atas kedua lutut Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya, \"Wahai Rasulullah, apakah Islam itu?\" beliau menjawab: \"Kamu menyerahkan sepenuhnya wajahmu kepada Allah dan kamu bersaksi bahwasanya, tidak ada tuhan yang berhak diibadahi melainkan Allah, dan Muhammad adalah hamba dan Rasulul-Nya. Kemudian kamu menunaikan shalat, dan membayar zakat.\" Jibril bertanya, \"Jika saya melakukan hal itu, apakah saya telah sah sebagai seorang Muslim?\" beliau menjawab: \"Ya.\" Kemudian Jibril bertanya lagi, \"Apakan Iman itu?\" beliau menjawab: \"Kamu beriman kepada Allah, hari akhirat, para malaikat-Nya, kitab-kitab-Nya, para Nabi-Nya, kematian, hidup setelah mati, surga dan neraka, hisab, mizan dan Qadar; yang baik atau yang buruk.\" Jibril bertanya lagi, \"Jika aku lakukan itu semua, apakah aku telah beriman?\" beliau menjawab: \"Ya.\" Kemudian Jibril bertanya.\"Apakah Ihsan itu wahai Rasulullah?\" beliau menjawab: \"Kamu beribadah kepada Allah seolah-olah kamu melihat-Nya, jika kamu tidak melihat-Nya, maka sesungguhnya Dia melihatmu.\" Jibril bertanya lagi, \"Jika saya lakukan hal itu, apakah telah berbuat ihsan?\" beliau menjawab: \"Ya.\" Abu Malik (perawi) mendengar jawaban Rasulullah shallallahu 'alaihi wasallam, namun ia tidak melihat orang berbicara dengannya dan tidak mendengar pembicaraannya. Jibril bertanya lagi, \"Kapankah datangnya hari kiamat wahai Rasulullah?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Subhaanallah, ada lima perkara ghaib tidak ada yang tahu kecuali Allah. '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim. Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakannya besok. Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) ' (Qs. Luqman: 31). Jibril berkata, \"Wahai Rasulullah, jika engkau mau maka akan saya beritahukan dua tanda yang akan terjadi sebelumnya?\" Beliau bersabda: \"Ceritakanlah kepadaku.\" Jibril pun berkata, \"Jika engkau melihat seorang budak perempuan melahirkan tuannya. Dan orang-orang saling berlomba untuk meninggikan bangunannya, serta orang-orang miskin berwatak keras menjadi pemimpin manusia.\" Kemudian Jibril bertanya, \"Siapakah mereka itu wahai Rasulullah?\" beliau menjawab: \"Arab dusun.\" Kemudian Jibril berlalu pergi dan tidak lagi terlihat jejaknya setelah itu. Beliau kemudian bersabda: \"Subhaanallah -tiga kali-, ia datang untuk mengajari manusia tentang agama mereka. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, ia tidak pernah datang kepadaku kecuali aku pasti mengenalnya. Kecuali kedatangannya pada kali ini.\" Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Abdul Hamid] telah menceritakan kepadaku [Syahr bin Hausyab] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang macam-macam dari kelas wanita…kemudian ia menyebutkan hadits tersebut. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah duduk dalam suatu majelis, kemudian datanglah Jibril 'Alahis Salam seraya duduk di depan Rasulullah shallallahu 'alaihi wasallam…lalu Ibnu Abbas menyebutkan hadits tersebut. Dan dalam hadits tersebut disebutkan, Rasulullah berkata, \"Jika kamu mau, saya akan menceritakan kepadamu mengenai tanga-tandanya selain itu.\" Jibril berkata, \"Tentu wahai Rasulullah, ceritakanlah padaku.\" Rasulullah bersabda: \"Jika kamu telah melihat budak wanita melahirkan tuannya…kemudian ia menyebutkan hadits tersebut.\""}],"31:34":[{"p":"Bukhari","n":48,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارِزًا يَوْمًا لِلنَّاسِ فَأَتَاهُ جِبْرِيلُ فَقَالَ مَا الْإِيمَانُ قَالَ الْإِيمَانُ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَبِلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ قَالَ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَسَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّهَا وَإِذَا تَطَاوَلَ رُعَاةُ الْإِبِلِ الْبُهْمُ فِي الْبُنْيَانِ فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ تَلَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ }الْآيَةَ ثُمَّ أَدْبَرَ فَقَالَ رُدُّوهُ فَلَمْ يَرَوْا شَيْئًا فَقَالَ هَذَا جِبْرِيلُ جَاءَ يُعَلِّمُ النَّاسَ دِينَهُمْقَالَ أَبُو عَبْد اللَّهِ جَعَلَ ذَلِك كُلَّهُ مِنْ الْإِيمَانِ","trj":"Telah menceritakan kepada kami [Musaddad] berkata, Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Abu Hayyan At Taimi] dari [Abu Zur'ah] dari [Abu Hurairah] berkata; bahwa Nabi shallallahu 'alaihi wasallam pada suatu hari muncul kepada para sahabat, lalu datang Malaikat Jibril 'Alaihis Salam yang kemudian bertanya: \"Apakah iman itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Iman adalah kamu beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya, pertemuan dengan-Nya, Rasul-Rasul-Nya, dan kamu beriman kepada hari berbangkit\". (Jibril 'Alaihis salam) berkata: \"Apakah Islam itu?\" Jawab Nabi shallallahu 'alaihi wasallam: \"Islam adalah kamu menyembah Allah dan tidak menyekutukannya dengan suatu apapun, kamu dirikan shalat, kamu tunaikan zakat yang diwajibkan, dan berpuasa di bulan Ramadlan\". (Jibril 'Alaihis salam) berkata: \"Apakah ihsan itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Kamu menyembah Allah seolah-olah melihat-Nya dan bila kamu tidak melihat-Nya sesungguhnya Dia melihatmu\". (Jibril 'Alaihis salam) berkata lagi: \"Kapan terjadinya hari kiamat?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Yang ditanya tentang itu tidak lebih tahu dari yang bertanya. Tapi aku akan terangkan tanda-tandanya; (yaitu); jika seorang budak telah melahirkan tuannya, jika para penggembala unta yang berkulit hitam berlomba-lomba membangun gedung-gedung selama lima masa, yang tidak diketahui lamanya kecuali oleh Allah\". Kemudian Nabi shallallahu 'alaihi wasallam membaca: \"Sesungguhnya hanya pada Allah pengetahuan tentang hari kiamat\" (QS. Luqman: 34). Setelah itu Jibril 'Alaihis salam pergi, kemudian Nabi shallallahu 'alaihi wasallam berkata; \"hadapkan dia ke sini.\" Tetapi para sahabat tidak melihat sesuatupun, maka Nabi bersabda; \"Dia adalah Malaikat Jibril datang kepada manusia untuk mengajarkan agama mereka.\" Abu Abdullah berkata: \"Semua hal yang diterangkan Beliau shallallahu 'alaihi wasallam dijadikan sebagai iman. "},{"p":"Ibnu Majah","n":3996,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ فَقَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّتَهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتْ الْحُفَاةُ الْعُرَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْغَنَمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ فَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah muncul di hadapan orang-orang, lalu datanglah seorang laki-laki kepada beliau seraya bertanya, \"Wahai Rasulullah, kapankah akan terjadi hari Kiamat?\" beliau menjawab: \"Tidaklah yang ditanya itu lebih mengetahui daripada yang bertanya, namun akan aku beritahukan kepadamu tanda-tandanya, yaitu; jika seorang budak melahirkan tuannya maka itulah tandanya. Dan apabila orang-orang yang tak beralas kaki menjadi pemimpin manusia maka itulah tandanya. Jika para penggembala kambing berlomba-lomba meninggikan bangunan rumah maka itulah tandanya. Dari lima hal ghaib yang tidak ada seorangpun yang mengetahuinya kecuali Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat: \"Sesungguhnya Allah, Hanya pada sisi-Nya sajalah pengetahuan tentang hari Kiamat; dan Dia-lah yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim…\", (Qs. Luqman: 34)."},{"p":"Muslim","n":10,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ ابْنِ عُلَيَّةَ قَالَ زُهَيْرٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ الْآخِرِ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَا تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتْ الْعُرَاةُ الْحُفَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْبَهْمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ تَلَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ ثُمَّ أَدْبَرَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا عَلَيَّ الرَّجُلَ فَأَخَذُوا لِيَرُدُّوهُ فَلَمْ يَرَوْا شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا جِبْرِيلُ جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا أَبُو حَيَّانَ التَّيْمِيُّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ فِي رِوَايَتِهِ إِذَا وَلَدَتْ الْأَمَةُ بَعْلَهَا يَعْنِي السَّرَارِيَّ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] semuanya dari [Ibnu Ulayyah], [Zuhair] berkata, telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Abu Hayyan] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada suatu hari berada di hadapan manusia, lalu seorang laki-laki mendatanginya seraya berkata, 'Wahai Rasulullah, apakah iman itu? ' Beliau menjawab, 'Kamu beriman kepada Allah, malaikat-Nya, kitab-Nya, beriman kepada kejadian pertemuan dengan-Nya, beriman kepada para Rasul-Nya, dan kamu beriman kepada hari kebangkitan yang akhir'. Dia bertanya, 'Wahai Rasulullah, apakah Islam itu? ' Beliau menjawab, 'Islam adalah kamu menyembah Allah dan tidak menyekutukan-Nya dengan sesuatu apa pun, mendirikan shalat yang wajib, membayar zakat yang difardlukan, dan berpuasa Ramadlan.' Dia bertanya lagi, 'Wahai Rasulullah, apakah ihsan itu? ' Beliau menjawab, 'Kamu menyembah Allah seakan-akan kamu melihat-Nya, maka jika kamu tidak melihat-Nya maka sesungguhnya Dia melihatmu.' Dia bertanya lagi, 'Wahai Rasulullah, kapankah hari kiamat itu? ' Beliau menjawab, 'Tidaklah orang yang ditanya tentangnya lebih mengetahui jawaban-Nya daripada orang yang bertanya, akan tetapi aku akan menceritakan kepadamu tentang tanda-tandanya; yaitu bila hamba wanita melahirkan tuan-Nya. Itulah salah satu tanda-tandanya. (Kedua) bila orang yang telanjang tanpa alas kaki menjadi pemimpin manusia. Itulah salah satu tanda-tandanya. (Ketiga) apabila penggembala kambing saling berlomba tinggi-tinggian dalam (mendirikan) bangunan. Itulah salah satu tanda-tandanya dalam lima tanda-tanda, tidak ada yang mengetahuinya kecuali Allah, \" kemudian beliau shallallahu 'alaihi wasallam membaca: '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim.Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakan-Nya besok.Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) ' (Qs. Luqman: 34). Kemudian laki-laki tersebut kembali pergi. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggil kembali laki-laki tersebut menghadapku'. Maka mereka mulai memanggilnya lagi, namun mereka tidak melihat sesuatu pun. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini Jibril, dia datang untuk mengajarkan manusia tentang agama mereka'.\" Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Abu Hayyan at-Taimi] dengan sanad ini hadits semisalnya, hanya saja dalam riwayatnya ada kalimat, 'Apabila hamba wanita melahirkan suaminya, yaitu para gundik'."},{"p":"Muslim","n":11,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ وَهُوَ ابْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلُونِي فَهَابُوهُ أَنْ يَسْأَلُوهُ فَجَاءَ رَجُلٌ فَجَلَسَ عِنْدَ رُكْبَتَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ لَا تُشْرِكُ بِاللَّهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصُومُ رَمَضَانَ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ وَتُؤْمِنَ بِالْقَدَرِ كُلِّهِ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ أَنْ تَخْشَى اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَا تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَتَى تَقُومُ السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَسَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا رَأَيْتَ الْمَرْأَةَ تَلِدُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ الْحُفَاةَ الْعُرَاةَ الصُّمَّ الْبُكْمَ مُلُوكَ الْأَرْضِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ رِعَاءَ الْبَهْمِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ مِنْ الْغَيْبِ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ قَرَأَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ ثُمَّ قَامَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوهُ عَلَيَّ فَالْتُمِسَ فَلَمْ يَجِدُوهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا جِبْرِيلُ أَرَادَ أَنْ تَعَلَّمُوا إِذْ لَمْ تَسْأَلُوا","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Umarah] -yaitu Ibnu al-Qa'qa'- dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kalian bertanyalah kepadaku'. Namun mereka takut dan segan untuk bertanya kepada beliau. Maka seorang laki-laki datang lalu duduk di hadapan kedua lutut beliau, laki-laki itu bertanya, 'Wahai Rasulullah, apakah Islam itu? ' Beliau menjawab, 'Islam adalah kamu tidak menyekutukan Allah dengan sesuatu apa pun, mendirikan shalat, membayar zakat, dan berpuasa Ramadlan.' Dia berkata, 'Kamu benar.' Lalu dia bertanya lagi, 'Wahai Rasulullah, apakah iman itu? ' Beliau menjawab, 'Kamu beriman kepada Allah, malaikat-Nya, kitab-Nya, beriman kepada kejadian pertemuan dengan-Nya, beriman kepada para Rasul-Nya, dan kamu beriman kepada hari kebangkitan serta beriman kepada takdir semuanya'. Dia berkata, 'Kamu benar'. Lalu dia bertanya lagi, 'Wahai Rasulullah, apakah ihsan itu? ' Beliau menjawab, 'Kamu takut (khasyyah) kepada Allah seakan-akan kamu melihat-Nya, maka jika kamu tidak melihat-Nya maka sesungguhnya Dia melihatmu.' Dia berkata, 'Kamu benar'. Lalu dia bertanya lagi, 'Wahai Rasulullah, kapankah hari kiamat itu? ' Beliau menjawab, 'Tidaklah orang yang ditanya tentangnya lebih mengetahui jawaban-Nya daripada orang yang bertanya, akan tetapi aku akan menceritakan kepadamu tentang tanda-tandanya; yaitu bila kamu melihat hamba wanita melahirkan tuan-Nya. Itulah salah satu tanda-tandanya. (Kedua) bila kamu melihat orang yang tanpa alas kaki telanjang, tuli, bisu menjadi pemimpin (manusia) di bumi. Itulah salah satu tanda-tandanya. (Ketiga) apabila kamu melihat penggembala kambing saling berlomba tinggi-tinggian dalam (mendirikan) bangunan. Itulah salah satu tanda-tandanya dalam lima tanda-tanda dari kegaiban, tidak ada yang mengetahuinya kecuali Allah, \" kemudian beliau membaca: '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim.Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakan-Nya besok. Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati.Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) \" (Qs. Luqman: 34). Kemudian laki-laki tersebut bangun (mengundurkan diri), maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggillah dia menghadapku! ' Maka dia dicari, namun mereka tidak mendapatkan-Nya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laki-laki ini adalah Jibril yang berkeinginan agar kalian mempelajari (agama) karena kalian tidak bertanya'.\""}]},"mapping_surah":[{"p":"Ahmad","n":1555,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ عَنْ عَامِرٍ أَوْ أَبِي عَامِرٍ أَوْ أَبِي مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي مَجْلِسٍ فِيهِ أَصْحَابُهُ جَاءَهُ جِبْرِيلُ عَلَيْهِ السَّلَام فِي غَيْرِ صُورَتِهِ يَحْسِبُهُ رَجُلًا مِنْ الْمُسْلِمِينَ فَسَلَّمَ عَلَيْهِ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ وَضَعَ جِبْرِيلُ يَدَهُ عَلَى رُكْبَتَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَهُ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ أَنْ تُسْلِمَ وَجْهَكَ لِلَّهِ وَتَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَسْلَمْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَالْمَلَائِكَةِ وَالْكِتَابِ وَالنَّبِيِّينَ وَالْمَوْتِ وَالْحَيَاةِ بَعْدَ الْمَوْتِ وَالْجَنَّةِ وَالنَّارِ وَالْحِسَابِ وَالْمِيزَانِ وَالْقَدَرِ كُلِّهِ خَيْرِهِ وَشَرِّهِ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ آمَنْتُ قَالَ نَعَمْ ثُمَّ قَالَ مَا الْإِحْسَانُ يَا رَسُولَ اللَّهِ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ كُنْتَ لَا تَرَاهُ فَهُوَ يَرَاكَ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَحْسَنْتُ قَالَ نَعَمْ وَيَسْمَعُ رَجْعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ وَلَا يَرَى الَّذِي يُكَلِّمُهُ وَلَا يَسْمَعُ كَلَامَهُ قَالَ فَمَتَى السَّاعَةُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ خَمْسٌ مِنْ الْغَيْبِ لَا يَعْلَمُهَا إِلَّا اللَّهُ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ السَّائِلُ يَا رَسُولَ اللَّهِ إِنْ شِئْتَ حَدَّثْتُكَ بِعَلَامَتَيْنِ تَكُونَانِ قَبْلَهَا فَقَالَ حَدِّثْنِي فَقَالَ إِذَا رَأَيْتَ الْأَمَةَ تَلِدُ رَبَّهَا وَيَطُولُ أَهْلُ الْبُنْيَانِ بِالْبُنْيَانِ وَكَانَ الْعَالَةُ الْجُفَاةُ رُءُوسَ النَّاسِ قَالَ وَمَنْ أُولَئِكَ يَا رَسُولَ اللَّهِ قَالَ الْعَرِيبُ قَالَ ثُمَّ وَلَّى فَلَمْ يُرَ طَرِيقُهُ بَعْدُ قَالَ سُبْحَانَ اللَّهِ ثَلَاثًا جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا جَاءَ لِي قَطُّ إِلَّا وَأَنَا أَعْرِفُهُ إِلَّا أَنْ تَكُونَ هَذِهِ الْمَرَّةُحَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا عَبْدُ الْحَمِيدِ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ عَنِ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَصْنَافِ النِّسَاءِ فَذَكَرَ الْحَدِيثَ مُلْصِقًا بِهِ قَالَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَجْلِسًا فَأَتَى جِبْرِيلُ عَلَيْهِ السَّلَام فَجَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ وَقَالَ فِيهِ إِنْ شِئْتَ حَدَّثْتُكَ بِمَعَالِمَ لَهَا دُونَ ذَلِكَ قَالَ أَجَلْ يَا رَسُولَ اللَّهِ فَحَدِّثْنِي وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَ الْأَمَةَ وَلَدَتْ رَبَّتَهَا فَذَكَرَ الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abdullah bin Abu Husain] ia berkata, telah menceritakan kepadaku [Syahr bin Hausyab] dari [Amir] atau [Abu Amir] atau [Abu Malik], bahwa ketika Nabi shallallahu 'alaihi wasallam sedang duduk-duduk di masjlisnya bersama dengan para sahabat, malaikat Jibril Alaihis Salam datang kepada beliau dengan rupa yang berbeda. Sehingga beliau mengira bahwa itu adalah seorang laki-laki biasa dari kaum muslimin. Jibril 'Alaihis salam lantas mengucapkan salam kepada beliau dan beliau pun membalas salamnya. Kemudian Jibril meletakkan tangannya di atas kedua lutut Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya, \"Wahai Rasulullah, apakah Islam itu?\" beliau menjawab: \"Kamu menyerahkan sepenuhnya wajahmu kepada Allah dan kamu bersaksi bahwasanya, tidak ada tuhan yang berhak diibadahi melainkan Allah, dan Muhammad adalah hamba dan Rasulul-Nya. Kemudian kamu menunaikan shalat, dan membayar zakat.\" Jibril bertanya, \"Jika saya melakukan hal itu, apakah saya telah sah sebagai seorang Muslim?\" beliau menjawab: \"Ya.\" Kemudian Jibril bertanya lagi, \"Apakan Iman itu?\" beliau menjawab: \"Kamu beriman kepada Allah, hari akhirat, para malaikat-Nya, kitab-kitab-Nya, para Nabi-Nya, kematian, hidup setelah mati, surga dan neraka, hisab, mizan dan Qadar; yang baik atau yang buruk.\" Jibril bertanya lagi, \"Jika aku lakukan itu semua, apakah aku telah beriman?\" beliau menjawab: \"Ya.\" Kemudian Jibril bertanya.\"Apakah Ihsan itu wahai Rasulullah?\" beliau menjawab: \"Kamu beribadah kepada Allah seolah-olah kamu melihat-Nya, jika kamu tidak melihat-Nya, maka sesungguhnya Dia melihatmu.\" Jibril bertanya lagi, \"Jika saya lakukan hal itu, apakah telah berbuat ihsan?\" beliau menjawab: \"Ya.\" Abu Malik (perawi) mendengar jawaban Rasulullah shallallahu 'alaihi wasallam, namun ia tidak melihat orang berbicara dengannya dan tidak mendengar pembicaraannya. Jibril bertanya lagi, \"Kapankah datangnya hari kiamat wahai Rasulullah?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Subhaanallah, ada lima perkara ghaib tidak ada yang tahu kecuali Allah. '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim. Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakannya besok. Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) ' (Qs. Luqman: 31). Jibril berkata, \"Wahai Rasulullah, jika engkau mau maka akan saya beritahukan dua tanda yang akan terjadi sebelumnya?\" Beliau bersabda: \"Ceritakanlah kepadaku.\" Jibril pun berkata, \"Jika engkau melihat seorang budak perempuan melahirkan tuannya. Dan orang-orang saling berlomba untuk meninggikan bangunannya, serta orang-orang miskin berwatak keras menjadi pemimpin manusia.\" Kemudian Jibril bertanya, \"Siapakah mereka itu wahai Rasulullah?\" beliau menjawab: \"Arab dusun.\" Kemudian Jibril berlalu pergi dan tidak lagi terlihat jejaknya setelah itu. Beliau kemudian bersabda: \"Subhaanallah -tiga kali-, ia datang untuk mengajari manusia tentang agama mereka. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, ia tidak pernah datang kepadaku kecuali aku pasti mengenalnya. Kecuali kedatangannya pada kali ini.\" Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Abdul Hamid] telah menceritakan kepadaku [Syahr bin Hausyab] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang macam-macam dari kelas wanita…kemudian ia menyebutkan hadits tersebut. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah duduk dalam suatu majelis, kemudian datanglah Jibril 'Alahis Salam seraya duduk di depan Rasulullah shallallahu 'alaihi wasallam…lalu Ibnu Abbas menyebutkan hadits tersebut. Dan dalam hadits tersebut disebutkan, Rasulullah berkata, \"Jika kamu mau, saya akan menceritakan kepadamu mengenai tanga-tandanya selain itu.\" Jibril berkata, \"Tentu wahai Rasulullah, ceritakanlah padaku.\" Rasulullah bersabda: \"Jika kamu telah melihat budak wanita melahirkan tuannya…kemudian ia menyebutkan hadits tersebut.\""},{"p":"Bukhari","n":31,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ ح قَالَ و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا لَمْ يَظْلِمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dan juga telah meriwayatkan hadits yang serupa ini, Telah menceritakan kepadaku [Bisyir bin Khalid Abu Muhammad Al 'Asykari] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: ketika turun ayat: \"Orang-orang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman\" para sahabat Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah diantara kami yang tidak berbuat zhalim? Maka Allah 'azza wajalla menurunkan (firman-Nya): \"Sesungguhnya kesyirikan adalah kezhaliman yang besar\". (QS. Luqman: 13) "},{"p":"Bukhari","n":48,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارِزًا يَوْمًا لِلنَّاسِ فَأَتَاهُ جِبْرِيلُ فَقَالَ مَا الْإِيمَانُ قَالَ الْإِيمَانُ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَبِلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ قَالَ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَسَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّهَا وَإِذَا تَطَاوَلَ رُعَاةُ الْإِبِلِ الْبُهْمُ فِي الْبُنْيَانِ فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ تَلَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ }الْآيَةَ ثُمَّ أَدْبَرَ فَقَالَ رُدُّوهُ فَلَمْ يَرَوْا شَيْئًا فَقَالَ هَذَا جِبْرِيلُ جَاءَ يُعَلِّمُ النَّاسَ دِينَهُمْقَالَ أَبُو عَبْد اللَّهِ جَعَلَ ذَلِك كُلَّهُ مِنْ الْإِيمَانِ","trj":"Telah menceritakan kepada kami [Musaddad] berkata, Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Abu Hayyan At Taimi] dari [Abu Zur'ah] dari [Abu Hurairah] berkata; bahwa Nabi shallallahu 'alaihi wasallam pada suatu hari muncul kepada para sahabat, lalu datang Malaikat Jibril 'Alaihis Salam yang kemudian bertanya: \"Apakah iman itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Iman adalah kamu beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya, pertemuan dengan-Nya, Rasul-Rasul-Nya, dan kamu beriman kepada hari berbangkit\". (Jibril 'Alaihis salam) berkata: \"Apakah Islam itu?\" Jawab Nabi shallallahu 'alaihi wasallam: \"Islam adalah kamu menyembah Allah dan tidak menyekutukannya dengan suatu apapun, kamu dirikan shalat, kamu tunaikan zakat yang diwajibkan, dan berpuasa di bulan Ramadlan\". (Jibril 'Alaihis salam) berkata: \"Apakah ihsan itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Kamu menyembah Allah seolah-olah melihat-Nya dan bila kamu tidak melihat-Nya sesungguhnya Dia melihatmu\". (Jibril 'Alaihis salam) berkata lagi: \"Kapan terjadinya hari kiamat?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Yang ditanya tentang itu tidak lebih tahu dari yang bertanya. Tapi aku akan terangkan tanda-tandanya; (yaitu); jika seorang budak telah melahirkan tuannya, jika para penggembala unta yang berkulit hitam berlomba-lomba membangun gedung-gedung selama lima masa, yang tidak diketahui lamanya kecuali oleh Allah\". Kemudian Nabi shallallahu 'alaihi wasallam membaca: \"Sesungguhnya hanya pada Allah pengetahuan tentang hari kiamat\" (QS. Luqman: 34). Setelah itu Jibril 'Alaihis salam pergi, kemudian Nabi shallallahu 'alaihi wasallam berkata; \"hadapkan dia ke sini.\" Tetapi para sahabat tidak melihat sesuatupun, maka Nabi bersabda; \"Dia adalah Malaikat Jibril datang kepada manusia untuk mengajarkan agama mereka.\" Abu Abdullah berkata: \"Semua hal yang diterangkan Beliau shallallahu 'alaihi wasallam dijadikan sebagai iman. "},{"p":"Bukhari","n":3117,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَنَزَلَتْ{ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah bercerita kepada kami [Abu Al Walid] telah bercerita kepada kami [Syu'bah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata; \"Ketika turun firman Allah Ta'ala yang artinya: (\"Orang-orang yang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman ….\") (QS al-An'am ayat 82), para sahabat Nabi shallallahu 'alaihi wasallam berkata; \"Siapa diantara kita yang tidak mencampur adukkan imannya dengan kezhaliman?\". Maka kemudian Allah Ta'ala menurunkan firman-Nya: (\"Janganlah kamu berbuat syirik (menyekutukan Allah), karena sesungguhnya syirik itu benar-benar kezhaliman yang besar\"). (QS Luqman ayat 13)."},{"p":"Bukhari","n":3118,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا لَا يَظْلِمُ نَفْسَهُ قَالَ لَيْسَ ذَلِكَ إِنَّمَا هُوَ الشِّرْكُ أَلَمْ تَسْمَعُوا مَا قَالَ لُقْمَانُ لِابْنِهِ وَهُوَ يَعِظُهُ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah bercerita kepadaku [Ishaq] telah mengabarkan kepada kami ['Isa bin Yunus] telah bercerita kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata; \"Ketika turun firman Allah Ta'ala yang artinya: (\"Orang-orang yang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman ….\") (QS al-An'am ayat 82), membuat kaum muslimin menjadi ragu lalu mereka berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam, adakah orang di antara kami yang tidak menzhalimi dirinya?\". Maka beliau berkata: \"Bukan itu maksudnya. Sesungguhnya yang dimaksud dengan kezhaliman pada ayat itu adalah syirik. Apakah kalian belum pernah mendengar apa yang diucapkan Luqman kepada anaknya saat dia memberi pelajaran: (\"Wahai anakku, Janganlah kamu berbuat syirik (menyekutukan Allah), karena sesungguhnya syirik itu benar-benar kezhaliman yang besar\"). (QS Luqman ayat 13)."},{"p":"Bukhari","n":6073,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ بِذَاكَ أَلَا تَسْمَعُونَ إِلَى قَوْلِ لُقْمَانَ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Alqomah] dari [Abdullah] radliallahu 'anhu, mengatakan; 'Dikala diturunkan ayat; 'Sesungguhnya orang yang beriman dan tidak mencampur adukkan keimanan mereka dengan kezhaliman' (QS. Al an'am 82), para sahabat Nabi shallallahu 'alaihi wasallam merasa gusar, sehingga bertanya; 'Siapakah diantara kami yang tidak mencampur keimananya dengan kezjhaliman? ' Maka Rasulullah Shallallahu'alaihiwasallam menjawab; \"Bukan itu yang dimaksudkan, tidakkah kalian mendengar ucapan Luqman; 'sesungguhnya kesyirikan adalah kezhaliman yang besar\" (QS. Luqman 13) "},{"p":"Ibnu Majah","n":790,"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ هَاشِمِ بْنِ الْبَرِيدِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا الظُّهْرَ فَنَسْمَعُ مِنْهُ الْآيَةَ بَعْدَ الْآيَاتِ مِنْ سُورَةِ لُقْمَانَ وَالذَّارِيَاتِ","trj":"Telah menceritakan kepada kami [Uqbah bin Mukram] berkata, telah menceritakan kepada kami [Salm bin Qutaibah] dari [Hasyim bin Al Barid] dari [Abu Ishaq] dari [Al Barra` bin Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat zhuhur bersama kami, lalu kami mendengar beliau membaca surat Luqman dan Adz Dzariyat ayat demi ayat. \" "},{"p":"Ibnu Majah","n":3996,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ فَقَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّتَهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتْ الْحُفَاةُ الْعُرَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْغَنَمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ فَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah muncul di hadapan orang-orang, lalu datanglah seorang laki-laki kepada beliau seraya bertanya, \"Wahai Rasulullah, kapankah akan terjadi hari Kiamat?\" beliau menjawab: \"Tidaklah yang ditanya itu lebih mengetahui daripada yang bertanya, namun akan aku beritahukan kepadamu tanda-tandanya, yaitu; jika seorang budak melahirkan tuannya maka itulah tandanya. Dan apabila orang-orang yang tak beralas kaki menjadi pemimpin manusia maka itulah tandanya. Jika para penggembala kambing berlomba-lomba meninggikan bangunan rumah maka itulah tandanya. Dari lima hal ghaib yang tidak ada seorangpun yang mengetahuinya kecuali Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat: \"Sesungguhnya Allah, Hanya pada sisi-Nya sajalah pengetahuan tentang hari Kiamat; dan Dia-lah yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim…\", (Qs. Luqman: 34)."},{"p":"Muslim","n":10,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ ابْنِ عُلَيَّةَ قَالَ زُهَيْرٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ الْآخِرِ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَا تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتْ الْعُرَاةُ الْحُفَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْبَهْمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ تَلَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ ثُمَّ أَدْبَرَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا عَلَيَّ الرَّجُلَ فَأَخَذُوا لِيَرُدُّوهُ فَلَمْ يَرَوْا شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا جِبْرِيلُ جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا أَبُو حَيَّانَ التَّيْمِيُّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ فِي رِوَايَتِهِ إِذَا وَلَدَتْ الْأَمَةُ بَعْلَهَا يَعْنِي السَّرَارِيَّ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] semuanya dari [Ibnu Ulayyah], [Zuhair] berkata, telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Abu Hayyan] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada suatu hari berada di hadapan manusia, lalu seorang laki-laki mendatanginya seraya berkata, 'Wahai Rasulullah, apakah iman itu? ' Beliau menjawab, 'Kamu beriman kepada Allah, malaikat-Nya, kitab-Nya, beriman kepada kejadian pertemuan dengan-Nya, beriman kepada para Rasul-Nya, dan kamu beriman kepada hari kebangkitan yang akhir'. Dia bertanya, 'Wahai Rasulullah, apakah Islam itu? ' Beliau menjawab, 'Islam adalah kamu menyembah Allah dan tidak menyekutukan-Nya dengan sesuatu apa pun, mendirikan shalat yang wajib, membayar zakat yang difardlukan, dan berpuasa Ramadlan.' Dia bertanya lagi, 'Wahai Rasulullah, apakah ihsan itu? ' Beliau menjawab, 'Kamu menyembah Allah seakan-akan kamu melihat-Nya, maka jika kamu tidak melihat-Nya maka sesungguhnya Dia melihatmu.' Dia bertanya lagi, 'Wahai Rasulullah, kapankah hari kiamat itu? ' Beliau menjawab, 'Tidaklah orang yang ditanya tentangnya lebih mengetahui jawaban-Nya daripada orang yang bertanya, akan tetapi aku akan menceritakan kepadamu tentang tanda-tandanya; yaitu bila hamba wanita melahirkan tuan-Nya. Itulah salah satu tanda-tandanya. (Kedua) bila orang yang telanjang tanpa alas kaki menjadi pemimpin manusia. Itulah salah satu tanda-tandanya. (Ketiga) apabila penggembala kambing saling berlomba tinggi-tinggian dalam (mendirikan) bangunan. Itulah salah satu tanda-tandanya dalam lima tanda-tanda, tidak ada yang mengetahuinya kecuali Allah, \" kemudian beliau shallallahu 'alaihi wasallam membaca: '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim.Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakan-Nya besok.Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) ' (Qs. Luqman: 34). Kemudian laki-laki tersebut kembali pergi. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggil kembali laki-laki tersebut menghadapku'. Maka mereka mulai memanggilnya lagi, namun mereka tidak melihat sesuatu pun. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini Jibril, dia datang untuk mengajarkan manusia tentang agama mereka'.\" Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Abu Hayyan at-Taimi] dengan sanad ini hadits semisalnya, hanya saja dalam riwayatnya ada kalimat, 'Apabila hamba wanita melahirkan suaminya, yaitu para gundik'."},{"p":"Muslim","n":11,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ وَهُوَ ابْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلُونِي فَهَابُوهُ أَنْ يَسْأَلُوهُ فَجَاءَ رَجُلٌ فَجَلَسَ عِنْدَ رُكْبَتَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ لَا تُشْرِكُ بِاللَّهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصُومُ رَمَضَانَ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ وَتُؤْمِنَ بِالْقَدَرِ كُلِّهِ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ أَنْ تَخْشَى اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَا تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ صَدَقْتَ قَالَ يَا رَسُولَ اللَّهِ مَتَى تَقُومُ السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَسَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا رَأَيْتَ الْمَرْأَةَ تَلِدُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ الْحُفَاةَ الْعُرَاةَ الصُّمَّ الْبُكْمَ مُلُوكَ الْأَرْضِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ رِعَاءَ الْبَهْمِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ مِنْ الْغَيْبِ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ قَرَأَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }قَالَ ثُمَّ قَامَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوهُ عَلَيَّ فَالْتُمِسَ فَلَمْ يَجِدُوهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا جِبْرِيلُ أَرَادَ أَنْ تَعَلَّمُوا إِذْ لَمْ تَسْأَلُوا","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Umarah] -yaitu Ibnu al-Qa'qa'- dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kalian bertanyalah kepadaku'. Namun mereka takut dan segan untuk bertanya kepada beliau. Maka seorang laki-laki datang lalu duduk di hadapan kedua lutut beliau, laki-laki itu bertanya, 'Wahai Rasulullah, apakah Islam itu? ' Beliau menjawab, 'Islam adalah kamu tidak menyekutukan Allah dengan sesuatu apa pun, mendirikan shalat, membayar zakat, dan berpuasa Ramadlan.' Dia berkata, 'Kamu benar.' Lalu dia bertanya lagi, 'Wahai Rasulullah, apakah iman itu? ' Beliau menjawab, 'Kamu beriman kepada Allah, malaikat-Nya, kitab-Nya, beriman kepada kejadian pertemuan dengan-Nya, beriman kepada para Rasul-Nya, dan kamu beriman kepada hari kebangkitan serta beriman kepada takdir semuanya'. Dia berkata, 'Kamu benar'. Lalu dia bertanya lagi, 'Wahai Rasulullah, apakah ihsan itu? ' Beliau menjawab, 'Kamu takut (khasyyah) kepada Allah seakan-akan kamu melihat-Nya, maka jika kamu tidak melihat-Nya maka sesungguhnya Dia melihatmu.' Dia berkata, 'Kamu benar'. Lalu dia bertanya lagi, 'Wahai Rasulullah, kapankah hari kiamat itu? ' Beliau menjawab, 'Tidaklah orang yang ditanya tentangnya lebih mengetahui jawaban-Nya daripada orang yang bertanya, akan tetapi aku akan menceritakan kepadamu tentang tanda-tandanya; yaitu bila kamu melihat hamba wanita melahirkan tuan-Nya. Itulah salah satu tanda-tandanya. (Kedua) bila kamu melihat orang yang tanpa alas kaki telanjang, tuli, bisu menjadi pemimpin (manusia) di bumi. Itulah salah satu tanda-tandanya. (Ketiga) apabila kamu melihat penggembala kambing saling berlomba tinggi-tinggian dalam (mendirikan) bangunan. Itulah salah satu tanda-tandanya dalam lima tanda-tanda dari kegaiban, tidak ada yang mengetahuinya kecuali Allah, \" kemudian beliau membaca: '(Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim.Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakan-Nya besok. Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati.Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal) \" (Qs. Luqman: 34). Kemudian laki-laki tersebut bangun (mengundurkan diri), maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggillah dia menghadapku! ' Maka dia dicari, namun mereka tidak mendapatkan-Nya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laki-laki ini adalah Jibril yang berkeinginan agar kalian mempelajari (agama) karena kalian tidak bertanya'.\""},{"p":"Muslim","n":177,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَا يَظْلِمُ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ هُوَ كَمَا تَظُنُّونَ إِنَّمَا هُوَ كَمَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ ح و حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ إِدْرِيسَ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ قَالَ أَبُو كُرَيْبٍ قَالَ ابْنُ إِدْرِيسَ حَدَّثَنِيهِ أَوَّلًا أَبِي عَنْ أَبَانَ بْنِ تَغْلِبَ عَنْ الْأَعْمَشِ ثُمَّ سَمِعْتُهُ مِنْهُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dan [Abu Mu'awiyah] serta [Waki'] dari [al-A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dia berkata, \"Ketika turun ayat: '(Orang-orang yang beriman, dan iman mereka belum bercampur dengan kezhaliman) ' (Qs. Al An'am: 82), maka para sahabat merasa berat terhadap hal tersebut seraya berkata, 'Wahai Rasulullah, siapakah di antara kita yang tidak mendzalimi dirinya! ' Beliau menjawab: 'Hal itu tidaklah seperti yang kalian maksudkan. Ia adalah sebagaimana yang dikatakan Luqman kepada anaknya: '(Wahai anakku, janganlah kamu mensyirikkan Allah. Sesungguhnya syirik adalah kezhaliman yang besar) '. (Qs. Luqman: 13). Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Kasyram] keduanya berkata, telah mengabarkan kepada kami [Isa] yaitu -Ibnu Yunus-. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Minjab bin al-Harits at-Tamimi] telah mengabarkan kepada kami [Ibnu Mushir]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Idris] semuanya dari [al-A'masy] dengan sanad ini, [Abu Kuraib] berkata, [Ibnu Idris] berkata, telah menceritakan kepadaku tentangnya pertama kali [bapakku] dari [Aban bin Taghlib] dari [al-A'masy] kemudian aku mendengarnya darinya.\""},{"p":"Nasa'i","n":959,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ قَالَ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْبَرِيدِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكُنَّا نُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَنَسْمَعُ مِنْهُ الْآيَةَ بَعْدَ الْآيَاتِ مِنْ سُورَةِ لُقْمَانَ وَالذَّارِيَاتِ","trj":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim bin Shudran] dia berkata; Telah mengabarkan kepada kami [Salm bin Qutaibah] dia berkata; Telah mengabarkan kepada kami [Hasyim bin Al Barid] dari [Abu Ishaq] dari [Abu Bara'] dia berkata; \"Kami shalat zhuhur di belakang Rasulullah Shallallahu'alaihi wasallam, kemudian kami mendengar satu ayat setelah beberapa ayat dari surat Luqman dan Adzariyat.\""},{"p":"Tirmidzi","n":2853,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ وَأَيُّنَا لَا يَظْلِمُ نَفْسَهُ قَالَ لَيْسَ ذَلِكَ إِنَّمَا هُوَ الشِّرْكُ أَلَمْ تَسْمَعُوا مَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khusyram] telah mengabarkan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; \"Saat turun ayat Orang-orang yang beriman dan tidak mencampuradukkan iman mereka dengan kezhaliman QS Al An`am: 82, kaum muslimin merasa berat karenanya dan bertanya; \"Wahai Rasulullah, adakah diantara kami yang tidak pernah mendzalimi dirinya?\" Beliau bersabda: \"Bukan begitu, maksudnya adalah syirk, bukankah kalian mendengar apa yang dikatakan Luqman kepada anaknya? Wahai anakku janganlah engkau mempersekutukan Allah, sesungguhnya syirik itu adalah kedzhaliman yang besar. QS Luqman: 13. Abu Isa mengatakan bahwa hadits ini hasan shahih."}]};
